import{_ as e,o as t,c as i,a3 as d}from"./chunks/framework.BveOjhN0.js";const g=JSON.parse('{"title":"XiHan.Framework.Upgrade","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/upgrade.md","filePath":"cosmos/framework/packages/upgrade.md","lastUpdated":1783216089000}'),r={name:"cosmos/framework/packages/upgrade.md"};function o(s,a,n,l,c,p){return t(),i("div",null,[...a[0]||(a[0]=[d(`<h1 id="xihan-framework-upgrade" tabindex="-1">XiHan.Framework.Upgrade <a class="header-anchor" href="#xihan-framework-upgrade" aria-label="Permalink to &quot;XiHan.Framework.Upgrade&quot;">​</a></h1><blockquote><p>升级引擎：版本存储、迁移执行、分布式锁、启动自动检查。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Upgrade</code></li><li><strong>模块类</strong>：<code>XiHanUpgradeModule</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Upgrade 是分布式安全升级的底层引擎与流程编排。它把「检测版本 → 抢分布式锁 → 进维护模式 → 按序执行迁移脚本 → 回写版本 → （可选）替换文件/滚动重启」这一整套升级流程抽象成统一编排，并对每个环节留下可插拔扩展点。它只提供基础能力与抽象，具体的数据库存储、锁实现、迁移执行由业务侧模块提供实现。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>应用启动或运维时，需要判断当前应用/数据库版本是否落后并自动升级。</li><li>多节点部署下，需要用分布式锁保证同一时刻只有一个节点执行升级。</li><li>按语义化版本发现、排序并幂等执行 SQL 迁移脚本，避免重复执行。</li><li>升级期间需要维护模式、程序文件替换、滚动重启等运维动作的统一编排。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Upgrade</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanUpgradeModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块会读取配置节 <code>XiHan:Upgrade</code>，并为各扩展点注册默认实现（<code>TryAdd</code>，可被业务侧替换）。默认实现中版本存储与锁均为内存版（<code>InMemoryUpgradeVersionStore</code> / <code>InMemoryUpgradeLockProvider</code>），生产环境通常需要业务侧替换为持久化 / 分布式实现。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>版本存储与状态管理</strong>：<code>IUpgradeVersionStore</code> 负责建表、获取或创建版本记录、写升级中/完成/失败状态、追加并去重迁移历史。</li><li><strong>迁移执行</strong>：<code>UpgradeEngine</code> 按语义化版本分组排序脚本，逐条幂等执行（已有历史则跳过），通过 <code>IUpgradeMigrationExecutor</code> 执行 SQL 并保证事务。</li><li><strong>分布式锁</strong>：<code>IUpgradeLockProvider</code> 抢占带过期时间的资源锁，<code>IUpgradeLockToken</code>（<code>IAsyncDisposable</code>）负责释放，确保集群内单节点升级。</li><li><strong>启动自动检查</strong>：<code>XiHanUpgradeModule</code> 在 <code>OnPostApplicationInitializationAsync</code> 中，当 <code>EnableAutoCheckOnStartup=true</code> 时调用 <code>IUpgradeStatusService.EnsureInitializedAsync</code> 初始化。</li><li><strong>语义化版本比较</strong>：<code>SemanticVersion</code> 提供 major/minor/patch 解析与比较，用于强制升级判定与脚本排序。</li><li><strong>主节点 / 多租户编排</strong>：可配置仅主节点执行升级，并支持多租户隔离逐租户升级。</li><li><strong>运维扩展</strong>：维护模式、程序文件替换、滚动重启均为可插拔扩展点（默认提供空实现）。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>XiHanUpgradeModule</code></td><td>升级模块，注册服务并在启动后触发自动检查</td></tr><tr><td><code>IUpgradeEngine</code> / <code>UpgradeEngine</code></td><td>升级引擎，编排检测、锁、迁移、回写全流程</td></tr><tr><td><code>IUpgradeCoordinator</code></td><td>升级协调器，后台启动升级</td></tr><tr><td><code>IUpgradeStatusService</code></td><td>升级状态服务，初始化与查询版本快照/状态</td></tr><tr><td><code>IUpgradeVersionStore</code></td><td>版本与升级状态存储、迁移历史</td></tr><tr><td><code>IUpgradeMigrationExecutor</code></td><td>迁移脚本执行器（内部保证事务）</td></tr><tr><td><code>IUpgradeLockProvider</code> / <code>IUpgradeLockToken</code></td><td>分布式锁提供者与锁令牌</td></tr><tr><td><code>IUpgradeScriptProvider</code></td><td>迁移脚本发现来源（默认 <code>FileSystemUpgradeScriptProvider</code>）</td></tr><tr><td><code>SemanticVersion</code></td><td>语义化版本解析与比较</td></tr><tr><td><code>XiHanUpgradeOptions</code></td><td>升级选项（配置节 <code>XiHan:Upgrade</code>）</td></tr><tr><td><code>UpgradeStatus</code></td><td>升级状态枚举（Normal/Upgrading/Completed/Failed）</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li><a href="./core">XiHan.Framework.Core</a> — 模块化生命周期与依赖注入基础。</li><li><a href="./multitenancy-abstractions">XiHan.Framework.MultiTenancy.Abstractions</a> — 多租户抽象，支撑逐租户隔离升级。</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./data">XiHan.Framework.Data</a> — 数据访问层，业务侧通常在此实现版本存储与迁移执行。</li><li><a href="./timing">XiHan.Framework.Timing</a> — 时间处理，升级历史与状态记录常用。</li></ul>`,20)])])}const k=e(r,[["render",o]]);export{g as __pageData,k as default};
